import React from 'react';
import { motion } from 'framer-motion';
import Container from '../layout/Container';
import Section from '../layout/Section';
import Card from '../ui/Card';
import { fadeUp, staggerContainer } from '../../animations/motionVariants';

const Value = () => {
  const valueProps = [
    {
      title: 'Precision Engineering',
      description: 'Meticulous attention to detail in every line of code, ensuring robust and scalable solutions.'
    },
    {
      title: 'Client-First Execution',
      description: 'Your vision drives the process. Transparent communication and collaborative decision-making.'
    },
    {
      title: 'Performance Obsessed',
      description: 'Lightning-fast load times, optimized algorithms, and seamless user experiences.'
    }
  ];

  return (
    <Section className="bg-secondary">
      <Container>
        <motion.div
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          variants={staggerContainer}
        >
          {/* Section Header */}
          <motion.div
            variants={fadeUp}
            className="text-center mb-20"
          >
            <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-text-primary mb-6">
              Why Visionary Teams Work With Me
            </h2>
            <p className="text-lg text-text-secondary max-w-2xl mx-auto">
              The principles that drive exceptional results.
            </p>
          </motion.div>

          {/* 3-Column Grid */}
          <div className="grid md:grid-cols-3 gap-8">
            {valueProps.map((item, index) => (
              <motion.div
                key={index}
                variants={fadeUp}
                custom={index}
                whileHover={{ 
                  y: -5,
                }}
                transition={{ type: "spring", stiffness: 400, damping: 10 }}
              >
                <Card className="h-full border border-white/10 hover:border-accent/50">
                  <h3 className="text-2xl font-bold text-text-primary mb-4 hover:text-accent transition-colors duration-300">
                    {item.title}
                  </h3>
                  <p className="text-text-secondary leading-relaxed">
                    {item.description}
                  </p>
                </Card>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </Container>
    </Section>
  );
};

export default Value;
